const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const allowedDestinations = ['https://example.com'];
const blockedIPRanges = [/^10\.0\./, /^172\.16\./, /^192\.168\./];

function isAllowedDestination(url) {
  return allowedDestinations.includes(url);
}

function isBlockedIP(request) {
  const ip = request.ip;
  for (const pattern of blockedIPRanges) {
    if (pattern.test(ip)) {
      return true;
    }
  }
  return false;
}

app.post('/webhook', async (request, response) => {
  try {
    if (!isAllowedDestination(request.headers['x-forwarded-url'])) {
      return response.status(403).send('Forbidden');
    }

    const destinationUrl = request.body.url;
    if (!destinationUrl || !isAllowedDestination(destinationUrl)) {
      return response.status(400).send('Invalid URL');
    }

    const headers = {};
    for (const key in request.headers) {
      if (key !== 'x-forwarded-url' && key !== 'host') {
        headers[key] = request.headers[key];
      }
    }

    try {
      const result = await axios.get(destinationUrl, { headers });
      return response.status(result.status).send(result.data);
    } catch (error) {
      console.error(error);
      return response.status(500).send('Internal Server Error');
    }
  } catch (error) {
    console.error(error);
    return response.status(500).send('Internal Server Error');
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});